#' }
#'
#' @export
enhancedBayesianCorrelation <- function(
    data,
    variables,
    prior = TRUE,
    posterior = TRUE,
    apaReport = TRUE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("enhancedBayesianCorrelation requires jmvcore to be installed (restart may be required)")

    if ( ! missing(variables)) variables <- jmvcore::resolveQuo(jmvcore::enquo(variables))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(variables), variables, NULL))


    options <- enhancedBayesianCorrelationOptions$new(
        variables = variables,
        prior = prior,
        posterior = posterior,
        apaReport = apaReport)

    analysis <- enhancedBayesianCorrelationClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

